  1→import React, { useState, useEffect } from 'react';
  2→import { User } from '../types';
  3→import {
  4→  User as UserIcon, Mail, Key, Bell, LogOut, Fuel, Check, Copy, AlertTriangle,
  5→  Droplet, Database, CreditCard, ShieldCheck, LayoutList, History, FileText,
  6→  Download, Loader2, Sparkles, FolderOpen, TrendingUp, Zap, ArrowUpRight
  7→} from 'lucide-react';
  8→import jsPDF from 'jspdf';
  9→import StripeCheckout from '../components/StripeCheckout';
 10→
 11→interface AccountProps {
 12→  user: User | null;
 13→  onLogout: () => void;
 14→  onNavigate: (view: any) => void;
 15→  onUpgrade: (plan: 'free' | 'pro' | 'enterprise') => void;
 16→  projectCount: number;
 17→  maxProjects: number;
 18→  initialTab?: 'profile' | 'subscription' | 'billing';
 19→}
 20→
 21→const Account: React.FC<AccountProps> = ({ user, onLogout, onNavigate, onUpgrade, projectCount, maxProjects, initialTab = 'profile' }) => {
 22→  const [activeTab, setActiveTab] = useState<'profile' | 'subscription' | 'billing'>(initialTab);
 23→  const [apiKeyCopied, setApiKeyCopied] = useState(false);
 24→  const [isProcessing, setIsProcessing] = useState(false);
 25→  const [upgradeModal, setUpgradeModal] = useState<{ planId: string; planName: string; newPrice: number } | null>(null);
 26→  const [paymentStep, setPaymentStep] = useState<'recap' | 'payment' | 'success'>('recap');
 27→  const [paidAmount, setPaidAmount] = useState(0);
 28→  const [paymentHistory, setPaymentHistory] = useState([
 29→    { id: 'INV-2024-003', date: '01/03/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
 30→    { id: 'INV-2024-002', date: '01/02/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
 31→    { id: 'INV-2024-001', date: '15/01/2024', amount: 49.00, desc: 'Pack GTO Gas (La Pompe)', status: 'Payé' },
 32→  ]);
 33→
 34→  useEffect(() => {
 35→    setActiveTab(initialTab);
 36→  }, [initialTab]);
 37→
 38→  if (!user) return null;
 39→
 40→  // ── Helpers ──
 41→
 42→  const handleCopyApiKey = () => {
 43→    navigator.clipboard.writeText(`cb_pk_live_${user.id.substring(0, 8)}_${Math.random().toString(36).substr(2, 9)}`);
 44→    setApiKeyCopied(true);
 45→    setTimeout(() => setApiKeyCopied(false), 2000);
 46→  };
 47→
 48→  const getPlanDetails = (plan: string) => {
 49→    switch (plan) {
 50→      case 'enterprise':
 51→        return { name: 'Agency', marketingName: 'La Citerne', icon: <Database size={14} className="fill-current" />, style: 'bg-purple-500/10 text-purple-500 border-white/[0.1] shadow-[0_0_15px_rgba(168,85,247,0.1)]' };
 52→      case 'pro':
 53→        return { name: 'Pro', marketingName: 'La Pompe', icon: <Fuel size={14} className="fill-current" />, style: 'bg-purple-500/10 text-purple-400 border-primary/20 shadow-[0_0_15px_rgba(16,185,129,0.1)]' };
 54→      default:
 55→        return { name: 'Starter', marketingName: 'Le Jerrican', icon: <Droplet size={14} />, style: 'bg-white/[0.04] text-gray-300 border-white/[0.08]' };
 56→    }
 57→  };
 58→
 59→  const planDetails = getPlanDetails(user.plan);
 60→  const projectPercentage = maxProjects >= 1000 ? 15 : Math.min((projectCount / maxProjects) * 100, 100);
 61→  const isAtLimit = projectCount >= maxProjects && maxProjects < 1000;
 62→
 63→  // ── Pricing data ──
 64→
 65→  const plans = [
 66→    {
 67→      id: 'free', name: 'Starter', price: 29, period: '/mois',
 68→      icon: <Droplet size={24} />, current: user.plan === 'free',
 69→      features: ['1 Projet Actif / mois', 'Audit manuel', 'Support communauté'],
 70→      cta: 'Plan Actuel',
 71→    },
 72→    {
 73→      id: 'pro', name: 'Pro', price: 89, period: '/mois', popular: true,
 74→      icon: <Fuel size={24} />, current: user.plan === 'pro',
 75→      features: ['Indexation IA', '3 Projets Actifs / mois', 'Monitoring Continu', 'Support Prioritaire', 'API Access (Beta)', 'Rapports PDF marque blanche'],
 76→      cta: 'Passer Pro',
 77→    },
 78→    {
 79→      id: 'enterprise', name: 'Agency', price: 299, period: '/mois',
 80→      icon: <Database size={24} />, current: user.plan === 'enterprise',
 81→      features: ['Indexation IA', 'Projets illimités', 'Dedicated Account Manager', 'API Full Access', 'SSO & Sécurité avancée', 'Formation AEO équipe'],
 82→      cta: 'Passer Agency',
 83→    },
 84→  ];
 85→
 86→  // Prix du plan actuel de l'utilisateur
 87→  const currentPlanPrice = user.plan === 'enterprise' ? 299 : user.plan === 'pro' ? 89 : 29;
 88→
 89→  const handleUpgradeClick = (planId: string) => {
 90→    const targetPlan = plans.find(p => p.id === planId);
 91→    if (!targetPlan || targetPlan.current) return;
 92→    setUpgradeModal({ planId, planName: targetPlan.name, newPrice: targetPlan.price });
 93→    setPaymentStep('payment');
 94→  };
 95→
 96→  const handleProcessPayment = () => {
 97→    if (!upgradeModal) return;
 98→    setIsProcessing(true);
 99→    setTimeout(() => {
100→      const amountPaid = upgradeModal.newPrice - currentPlanPrice;
101→      const now = new Date();
102→      const dateStr = now.toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' });
103→      const invoiceNum = `INV-${now.getFullYear()}-${String(paymentHistory.length + 1).padStart(3, '0')}`;
104→      const newInvoice = {
105→        id: invoiceNum,
106→        date: dateStr,
107→        amount: amountPaid,
108→        desc: `Upgrade ${planDetails.name} → ${upgradeModal.planName} (Prorata)`,
109→        status: 'Payé',
110→      };
111→      setPaymentHistory(prev => [newInvoice, ...prev]);
112→      setPaidAmount(amountPaid);
113→      onUpgrade(upgradeModal.planId as any);
114→      setIsProcessing(false);
115→      setPaymentStep('success');
116→    }, 2500);
117→  };
118→
119→  const handleCloseUpgradeModal = () => {
120→    setUpgradeModal(null);
121→    setPaymentStep('recap');
122→    setPaidAmount(0);
123→  };
124→
125→  // ── Invoice PDF ──
126→
127→  const generateInvoice = (payment: { id: string; date: string; amount: number; desc: string; status: string }) => {
128→    const doc = new jsPDF();
129→    doc.setFontSize(22);
130→    doc.setFont('helvetica', 'bold');
131→    doc.text('CitedBy.ai', 20, 20);
132→    doc.setFontSize(10);
133→    doc.setFont('helvetica', 'normal');
134→    doc.text(`Facture N° ${payment.id}`, 20, 30);
135→    doc.text(`Date : ${payment.date}`, 20, 35);
136→    doc.text('Facturé à :', 140, 30);
137→    doc.setFont('helvetica', 'bold');
138→    doc.text(user.name || 'Client', 140, 35);
139→    doc.setFont('helvetica', 'normal');
140→    doc.text(user.email || '', 140, 40);
141→    doc.line(20, 55, 190, 55);
142→    doc.setFont('helvetica', 'bold');
143→    doc.text('Description', 20, 62);
144→    doc.text('Montant HT', 160, 62);
145→    doc.line(20, 66, 190, 66);
146→    const priceHT = (payment.amount / 1.2).toFixed(2);
147→    const tva = (payment.amount - parseFloat(priceHT)).toFixed(2);
148→    doc.setFont('helvetica', 'normal');
149→    doc.text(payment.desc, 20, 75);
150→    doc.text(`${priceHT} €`, 160, 75);
151→    doc.line(20, 90, 190, 90);
152→    doc.text('Sous-total HT :', 130, 100);
153→    doc.text(`${priceHT} €`, 160, 100);
154→    doc.text('TVA (20%) :', 130, 107);
155→    doc.text(`${tva} €`, 160, 107);
156→    doc.setFont('helvetica', 'bold');
157→    doc.setFontSize(12);
158→    doc.text('Total TTC :', 130, 117);
159→    doc.text(`${payment.amount.toFixed(2)} €`, 160, 117);
160→    doc.setFontSize(8);
161→    doc.setFont('helvetica', 'italic');
162→    doc.text('Merci de votre confiance. Paiement effectué par CB.', 20, 140);
163→    doc.save(`Facture_${payment.id}.pdf`);
164→  };
165→
166→  // ── Render ──
167→
168→  return (
169→    <div className="w-full px-4 py-10 animate-in fade-in duration-500 min-h-screen">
170→
171→      {/* ── STEP 2 : PLEINE PAGE DE PAIEMENT (comme Recharge.tsx) ── */}
172→      {upgradeModal && paymentStep === 'payment' && (
173→        <div className="animate-in fade-in slide-in-from-right duration-500">
174→          <StripeCheckout
175→            mode="subscription"
176→            productName={`Plan ${upgradeModal.planName}`}
177→            productDescription={`Upgrade ${planDetails.name} → ${upgradeModal.planName}`}
178→            amount={upgradeModal.newPrice - currentPlanPrice}
179→            amountDetails={[
180→              { label: `Nouveau plan (${upgradeModal.planName})`, value: `${upgradeModal.newPrice.toFixed(2)} €` },
181→              { label: `Crédit plan ${planDetails.name}`, value: `- ${currentPlanPrice.toFixed(2)} €` },
182→              { label: 'À payer aujourd\'hui', value: `${(upgradeModal.newPrice - currentPlanPrice).toFixed(2)} €`, highlight: true, separator: true },
183→            ]}
184→            userEmail={user.email}
185→            onConfirm={handleProcessPayment}
186→            onBack={() => setPaymentStep('recap')}
187→            isProcessing={isProcessing}
188→          />
189→        </div>
190→      )}
191→
192→      {/* Contenu principal — masqué pendant le paiement */}
193→      {!(upgradeModal && paymentStep === 'payment') && (<>
194→
195→      {/* Header */}
196→      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
197→        <div className="flex items-center gap-4">
198→          <div className="w-14 h-14 bg-gradient-to-br from-purple-500 to-violet-600 rounded-2xl flex items-center justify-center text-white font-bold text-2xl shadow-lg shadow-purple-500/20 border-2 border-black">
199→            {user.name.charAt(0).toUpperCase()}
200→          </div>
201→          <div>
202→            <h1 className="text-3xl font-sans font-bold text-white">Compte & Plan</h1>
203→            <p className="text-gray-500 text-sm">Profil, abonnement, facturation</p>
204→          </div>
205→        </div>
206→        <button
207→          onClick={onLogout}
208→          className="flex items-center gap-2 px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-full transition-colors text-sm font-medium"
209→        >
210→          <LogOut size={16} /> Déconnexion
211→        </button>
212→      </div>
213→
214→      {/* Tabs */}
215→      <div className="flex justify-center mb-10">
216→        <div className="inline-flex bg-white/[0.04] p-1.5 rounded-2xl border border-white/[0.08] flex-wrap justify-center gap-1">
217→          {([
218→            { key: 'profile', icon: UserIcon, label: 'Profil' },
219→            { key: 'subscription', icon: ShieldCheck, label: 'Abonnement & Projets' },
220→            { key: 'billing', icon: CreditCard, label: 'Facturation' },
221→          ] as const).map(tab => (
222→            <button
223→              key={tab.key}
224→              onClick={() => setActiveTab(tab.key)}
225→              className={`px-5 py-2.5 rounded-2xl text-sm font-bold transition-all flex items-center gap-2 ${
226→                activeTab === tab.key
227→                  ? 'bg-gradient-to-r from-purple-500 to-violet-600 text-white shadow-lg'
228→                  : 'text-gray-500 hover:text-white'
229→              }`}
230→            >
231→              <tab.icon size={16} /> {tab.label}
232→            </button>
233→          ))}
234→        </div>
235→      </div>
236→
237→      {/* ═══════════════════════════════════════════════
238→          TAB 1 : PROFIL
239→          ═══════════════════════════════════════════════ */}
240→      {activeTab === 'profile' && (
241→        <div className="animate-in fade-in duration-300 grid lg:grid-cols-3 gap-8">
242→
243→          {/* Left: Profile Card + GTO Balance */}
244→          <div className="space-y-6">
245→            {/* Profile summary */}
246→            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] text-center relative overflow-hidden">
247→              <div className="absolute top-0 left-0 w-full h-24 bg-gradient-to-b from-white/5 to-transparent"></div>
248→              <div className="relative">
249→                <div className="w-24 h-24 mx-auto bg-gradient-to-br from-purple-500 to-violet-600 rounded-full flex items-center justify-center text-white font-bold text-4xl shadow-xl shadow-purple-500/20 mb-4 border-4 border-black">
250→                  {user.name.charAt(0).toUpperCase()}
251→                </div>
252→                <h2 className="text-xl font-bold text-white">{user.name}</h2>
253→                <p className="text-sm text-gray-500 mb-4">{user.email}</p>
254→                <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full border text-xs font-bold uppercase tracking-wide ${planDetails.style}`}>
255→                  {planDetails.icon}
256→                  {planDetails.marketingName}
257→                </div>
258→              </div>
259→            </div>
260→
261→            {/* GTO Gas balance */}
262→            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] relative overflow-hidden">
263→              <div className="flex justify-between items-start mb-4">
264→                <div className="p-3 bg-purple-500/10 rounded-2xl text-purple-400">
265→                  <Fuel size={24} />
266→                </div>
267→                <button
268→                  onClick={() => onNavigate('recharge')}
269→                  className="text-xs bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold px-3 py-1.5 rounded-full hover:brightness-110 transition-all"
270→                >
271→                  Recharger
272→                </button>
273→              </div>
274→              <p className="text-sm text-gray-500 mb-1">Solde GTO Gas</p>
275→              <div className="text-4xl font-bold text-white mb-2">{user.credits}</div>
276→              <div className="w-full bg-white/[0.08] h-1.5 rounded-full overflow-hidden">
277→                <div className="bg-purple-500 h-full rounded-full transition-all" style={{ width: `${Math.min((user.credits / 500) * 100, 100)}%` }}></div>
278→              </div>
279→              <p className="text-xs text-gray-500 mt-2">~{Math.floor(user.credits / 10)} audits restants</p>
280→            </div>
281→          </div>
282→
283→          {/* Right: Settings */}
284→          <div className="lg:col-span-2 space-y-8">
285→            {/* API Keys */}
286→            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
287→              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
288→                <Key size={20} className="text-purple-400" /> Clés API & Intégrations
289→              </h3>
290→              <div className="bg-black/40 border border-white/[0.08] rounded-2xl p-4 flex items-center justify-between gap-4">
291→                <div className="flex-1 overflow-hidden">
292→                  <p className="text-xs text-gray-500 mb-1 uppercase tracking-wider">Clé Publique</p>
293→                  <code className="text-sm text-purple-300 font-mono block truncate">cb_pk_live_{user.id.substring(0, 8)}...</code>
294→                </div>
295→                <button
296→                  onClick={handleCopyApiKey}
297→                  className="p-2 hover:bg-purple-500/10 rounded-full transition-colors text-gray-500 hover:text-white"
298→                  title="Copier la clé"
299→                >
300→                  {apiKeyCopied ? <Check size={18} className="text-purple-400" /> : <Copy size={18} />}
301→                </button>
302→              </div>
303→              <p className="text-xs text-gray-500 mt-3">
304→                Cette clé permet d'utiliser l'API CitedBy.ai. Ne la partagez jamais.
305→              </p>
306→            </div>
307→
308→            {/* Personal Info */}
309→            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
310→              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
311→                <UserIcon size={20} className="text-blue-400" /> Informations Personnelles
312→              </h3>
313→              <div className="grid md:grid-cols-2 gap-6">
314→                <div className="space-y-2">
315→                  <label className="text-sm font-medium text-gray-500">Nom Complet</label>
316→                  <input type="text" defaultValue={user.name} className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white focus:border-purple-500/50 outline-none" />
317→                </div>
318→                <div className="space-y-2">
319→                  <label className="text-sm font-medium text-gray-500">Email</label>
320→                  <input type="email" defaultValue={user.email} disabled className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-gray-500 cursor-not-allowed" />
321→                </div>
322→                <div className="space-y-2 md:col-span-2">
323→                  <label className="text-sm font-medium text-gray-500">Workspace / Entreprise</label>
324→                  <input type="text" defaultValue="Mon Espace Personnel" className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white focus:border-purple-500/50 outline-none" />
325→                </div>
326→              </div>
327→              <div className="mt-6 flex justify-end">
328→                <button className="btn-gradient px-6 py-2.5 text-white font-bold text-sm">Enregistrer les modifications</button>
329→              </div>
330→            </div>
331→
332→            {/* Notifications */}
333→            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
334→              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
335→                <Bell size={20} className="text-purple-400" /> Préférences de notification
336→              </h3>
337→              <div className="space-y-4">
338→                {[
339→                  { label: "Rapport d'audit terminé", desc: 'Recevoir un email quand une analyse est finie.', default: true },
340→                  { label: 'Alerte de baisse de score', desc: 'Notification si le score AEO chute de plus de 10%.', default: true },
341→                  { label: 'Offres & Nouveautés', desc: 'Newsletters produit et mises à jour.', default: false },
342→                ].map((pref, i) => (
343→                  <div key={i} className="flex items-start justify-between pb-4 border-b border-white/[0.06] last:border-0 last:pb-0">
344→                    <div>
345→                      <p className="text-sm font-medium text-white">{pref.label}</p>
346→                      <p className="text-xs text-gray-500 mt-0.5">{pref.desc}</p>
347→                    </div>
348→                    <label className="relative inline-flex items-center cursor-pointer">
349→                      <input type="checkbox" defaultChecked={pref.default} className="sr-only peer" />
350→                      <div className="w-11 h-6 bg-gray-700 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:start-[2px] after:bg-white after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-purple-500"></div>
351→                    </label>
352→                  </div>
353→                ))}
354→              </div>
355→            </div>
356→
357→            {/* Danger Zone */}
358→            <div className="border border-red-500/20 rounded-2xl p-6 bg-red-500/5">
359→              <h3 className="text-sm font-bold text-red-400 flex items-center gap-2 mb-2">
360→                <AlertTriangle size={16} /> Zone de danger
361→              </h3>
362→              <p className="text-xs text-gray-500 mb-4">La suppression du compte est irréversible. Toutes vos données seront perdues.</p>
363→              <button className="text-xs font-bold text-red-500 hover:text-red-400 border border-red-500/30 hover:bg-red-500/10 px-4 py-2 rounded-full transition-colors">
364→                Supprimer mon compte
365→              </button>
366→            </div>
367→          </div>
368→        </div>
369→      )}
370→
371→      {/* ═══════════════════════════════════════════════
372→          TAB 2 : ABONNEMENT & PROJETS
373→          ═══════════════════════════════════════════════ */}
374→      {activeTab === 'subscription' && (
375→        <div className="animate-in fade-in duration-300 space-y-8">
376→
377→          {/* Project Counter + Upgrade Banner */}
378→          <div className="grid md:grid-cols-2 gap-6">
379→
380→            {/* Project consumption counter */}
381→            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] relative overflow-hidden">
382→              <div className="absolute top-0 right-0 w-40 h-40 bg-purple-500/5 blur-3xl"></div>
383→              <div className="flex items-center gap-3 mb-5">
384→                <div className="p-3 bg-purple-500/10 rounded-2xl">
385→                  <FolderOpen size={22} className="text-purple-400" />
386→                </div>
387→                <div>
388→                  <p className="text-sm text-gray-500">Projets ce mois</p>
389→                  <p className="text-xs text-gray-600">Renouvellement mensuel automatique</p>
390→                </div>
391→              </div>
392→
393→              <div className="flex items-baseline gap-2 mb-3">
394→                <span className="text-5xl font-bold text-white">{projectCount}</span>
395→                <span className="text-2xl text-gray-600 font-bold">/</span>
396→                <span className="text-2xl text-gray-500 font-bold">{maxProjects >= 1000 ? '∞' : maxProjects}</span>
397→              </div>
398→
399→              <div className="w-full bg-white/[0.06] h-2.5 rounded-full overflow-hidden mb-3">
400→                <div
401→                  className={`h-full rounded-full transition-all duration-500 ${
402→                    isAtLimit ? 'bg-red-500' : projectPercentage > 66 ? 'bg-yellow-500' : 'bg-purple-500'
403→                  }`}
404→                  style={{ width: `${projectPercentage}%` }}
405→                ></div>
406→              </div>
407→
408→              {isAtLimit ? (
409→                <div className="flex items-center gap-2 text-red-400 text-sm font-medium">
410→                  <AlertTriangle size={14} />
411→                  Limite atteinte — Passez au plan supérieur
412→                </div>
413→              ) : (
414→                <p className="text-xs text-gray-500">
415→                  {maxProjects >= 1000 ? 'Projets illimités avec votre plan Agency' : `${maxProjects - projectCount} projet${maxProjects - projectCount > 1 ? 's' : ''} restant${maxProjects - projectCount > 1 ? 's' : ''} ce mois`}
416→                </p>
417→              )}
418→            </div>
419→
420→            {/* GTO Gas + Credits */}
421→            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] relative overflow-hidden">
422→              <div className="flex items-center gap-3 mb-5">
423→                <div className="p-3 bg-purple-500/10 rounded-2xl">
424→                  <Fuel size={22} className="text-purple-400" />
425→                </div>
426→                <div>
427→                  <p className="text-sm text-gray-500">Solde GTO Gas</p>
428→                  <p className="text-xs text-gray-600">Crédits de génération IA</p>
429→                </div>
430→              </div>
431→
432→              <div className="flex items-baseline gap-2 mb-3">
433→                <span className="text-5xl font-bold text-white">{user.credits}</span>
434→                <span className="text-lg text-gray-500">crédits</span>
